import React, { useState } from 'react';

const CreateDestination = ({ onAddDestination, onClose }) => {
    const [title, setTitle] = useState('');
    const [description, setDescription] = useState('');
    const [location, setLocation] = useState('');
    const [imagePreview, setImagePreview] = useState(null);

    const handleImageChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setImagePreview(reader.result);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = (e) => {
        e.preventDefault();

        const newDestination = {
            id: Date.now().toString(),
            title,
            description,
            location,
            image: imagePreview // juste pour l’aperçu, non sauvegardée
        };

        // Appel vers le parent (ou simuler ajout dans le mock)
        onAddDestination?.(newDestination);
        console.log('Nouvelle destination simulée (mock):', newDestination);

        // Réinitialisation et fermeture
        setTitle('');
        setDescription('');
        setLocation('');
        setImagePreview(null);
        onClose?.();
    };

    return (
        <div className="create-destination p-4 bg-white dark:bg-gray-800 rounded-xl shadow-md max-w-md mx-auto">
            <h2 className="text-xl font-semibold mb-4 text-gray-800 dark:text-gray-100">Créer une nouvelle destination</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
                <input
                    type="text"
                    placeholder="Titre"
                    value={title}
                    onChange={(e) => setTitle(e.target.value)}
                    className="w-full p-2 border rounded dark:bg-gray-700 dark:text-white"
                    required
                />
                <textarea
                    placeholder="Description"
                    value={description}
                    onChange={(e) => setDescription(e.target.value)}
                    className="w-full p-2 border rounded dark:bg-gray-700 dark:text-white"
                    required
                />
                <input
                    type="text"
                    placeholder="Localisation"
                    value={location}
                    onChange={(e) => setLocation(e.target.value)}
                    className="w-full p-2 border rounded dark:bg-gray-700 dark:text-white"
                    required
                />
                <input
                    type="file"
                    accept="image/*"
                    onChange={handleImageChange}
                    className="w-full p-2"
                />
                {imagePreview && (
                    <img src={imagePreview} alt="Preview" className="w-full h-40 object-cover rounded" />
                )}
                <div className="flex justify-end gap-2">
                    <button
                        type="button"
                        onClick={onClose}
                        className="px-4 py-2 bg-gray-300 dark:bg-gray-600 rounded hover:bg-gray-400 dark:hover:bg-gray-700"
                    >
                        Annuler
                    </button>
                    <button
                        type="submit"
                        className="px-4 py-2 bg-blue-600 text-white rounded hover:bg-blue-700"
                    >
                        Créer
                    </button>
                </div>
            </form>
        </div>
    );
};

export default CreateDestination;
